func unsafeWrapAppSrc(base *gobject.ObjectInstance) *AppSrcInstance {
	return &AppSrcInstance{
		BaseSrcInstance: gstbase.BaseSrcInstance{
			ElementInstance: gst.ElementInstance{
				ObjectInstance: gst.ObjectInstance{
					InitiallyUnownedInstance: gobject.InitiallyUnownedInstance{
						ObjectInstance: *base,
					},
				},
			},
		},
		URIHandlerInstance: gst.URIHandlerInstance{
			Instance: *base,
		},
	}
}

func init() {
	gobject.RegisterObjectCasting(
		TypeAppSrc,
		func (inst *gobject.ObjectInstance) gobject.Object {
			return unsafeWrapAppSrc(inst)
		},
	)
}

func marshalAppSrcInstance(p unsafe.Pointer) (any, error) {
	return gobject.ValueFromNative(p).Object(), nil
}

